// // This module implements a 4-bit DRAM cell with read and write operations.
// When the write signal is low, the data input should be stored in the cell.
// When the read signal is low, the stored data should be output.
module dram_cell (
    input wire [3:0] data_in,
    input wire read,
    input wire write,
    output reg [3:0] data_out
);

    reg [3:0] memory;

    always @(posedge write) begin
        memory <= data_in; // Write data to memory
    end

    always @(posedge read) begin
        data_out <= memory; // Read data from memory
    end

endmodule

